+    expect(t.mode).toBe(SDK_MODE_UNSET);
+    // Actual call in code still fires.
+    expect(t.observe('\nsetType("sequence");')).toBe(true);
+    expect(t.mode).toBe(SDK_MODE_SEQUENCE);
+  });
+});

